using System.ComponentModel;

namespace PopupMAUI
{
    public partial class MainPage : ContentPage
    {
        public MainPage()
        {
           InitializeComponent();
        }
        private void clickToShowPopup_Clicked(object sender, EventArgs e)
        {
            (this.BindingContext as ViewModel).IsOpen = true;
        }
     }
}


